mapper.select:
SELECT id, name, path, component, icon, parent_id, sort_order, type, permission_code, is_visible, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_menu WHERE is_deleted = 0
AND type = #{type}
ORDER BY parent_id, sort_order, create_date DESC

mapper.update:
UPDATE sp_menu
name = #{name}, path = #{path}, component = #{component}, icon = #{icon}, parent_id = #{parentId}, sort_order = #{sortOrder}, type = #{type}, permission_code = #{permissionCode}, is_visible = #{isVisible}, update_name = #{updateName}, update_id = #{updateId},
WHERE id = #{id}

mapper.select:
SELECT m.id, m.name, m.path, m.component, m.icon, m.parent_id, m.sort_order, m.type, m.permission_code, m.is_visible, m.is_deleted, m.create_name, m.create_id, m.create_date, m.update_name, m.update_id, m.update_date FROM sp_menu m LEFT JOIN sp_role_menu rm ON m.id = rm.menu_id WHERE rm.role_id IN
#{roleId}
AND m.is_deleted = 0 ORDER BY m.parent_id, m.sort_order
